import { prisma } from '../src/db.js';

async function main() {
  console.log("Starting cleanup script...");

  // We find campaigns generated by the seed script based on their names
  const seedCampaignNames = [
    "Q3 Cloud Solutions Sales Pitch",
    "TechCorp Full Stack Developer Screening",
    "Springfield Elementary Parent Check-ins",
    "Ocean Bank Satisfaction Survey"
  ];

  const campaigns = await prisma.campaign.findMany({
    where: {
      name: { in: seedCampaignNames }
    }
  });

  const campaignIds = campaigns.map(c => c.id);
  const callModuleIds = campaigns.map(c => c.callModuleId);

  if (campaignIds.length === 0) {
    console.log("No seed campaigns found to delete.");
    return;
  }

  console.log(`Found ${campaignIds.length} seed campaigns. Deleting associated data...`);

  // Delete Call Reports (handled by call-evaluation-service, but they are stored in the same db usually. Wait, CallReport isn't in this prisma schema, it's in the other service. I will ignore it or delete via raw query if needed, but Prisma cascade should handle it or it's separated).
  // Wait, I should delete from CallLog, CampaignContact, Contact
  
  await prisma.callLog.deleteMany({
    where: { campaignId: { in: campaignIds } }
  });
  console.log("- Deleted Call Logs");

  // We need to find Contacts linked to these campaigns to delete them too
  const campaignContacts = await prisma.campaignContact.findMany({
    where: { campaignId: { in: campaignIds } }
  });
  const contactIds = campaignContacts.map(cc => cc.contactId);

  await prisma.campaignContact.deleteMany({
    where: { campaignId: { in: campaignIds } }
  });
  console.log("- Deleted CampaignContacts");

  await prisma.campaign.deleteMany({
    where: { id: { in: campaignIds } }
  });
  console.log("- Deleted Campaigns");

  if (contactIds.length > 0) {
    await prisma.contact.deleteMany({
      where: { id: { in: contactIds } }
    });
    console.log(`- Deleted ${contactIds.length} Contacts`);
  }

  if (callModuleIds.length > 0) {
    await prisma.callModule.deleteMany({
      where: { id: { in: callModuleIds } }
    });
    console.log("- Deleted Call Modules");
  }
  
  // Clean up CallReport table using raw query since it might be defined in the eval service prisma schema
  try {
     await prisma.$executeRaw`DELETE FROM "CallReport" WHERE "campaignId" IN (${campaignIds.join("','")})`;
     console.log("- Deleted Evaluation Reports");
  } catch (e) {
     // Ignore if table doesn't exist
  }

  console.log("Cleanup finished successfully!");
}

main().catch(console.error).finally(() => prisma.$disconnect());
